import sys

def main():
    import bisect
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    A = list(map(int, data[2:2+M]))

    res = [0] * N
    for i in range(N):
        idx = bisect.bisect_left(A, i+1)
        if idx < M:
            res[i] = A[idx] - (i + 1)
        else:
            res[i] = 0  # This case won't happen as A_M = N

    for val in res:
        print(val)

if __name__ == "__main__":
    main()
